class Playground {
    async run(inputs) {
        // Parse input
        const heightsInput = inputs[0].split(',').map(v => parseInt(v.trim()));

        // Initialize visualization slots
        await this.heights.init(heightsInput);
        await this.vars.init([
            ["left", 0],
            ["right", heightsInput.length - 1],
            ["maxArea", 0],
            ["currentArea", 0]
        ]);

        let left = 0;
        let right = heightsInput.length - 1;
        let maxArea = 0;

        this.log("Starting two-pointer approach from both ends.");
        await this.await();

        while (left < right) {
            // Highlight the current boundaries
            this.heights.highlight(left, "#3b82f6"); // Blue
            this.heights.highlight(right, "#3b82f6");

            const hLeft = heightsInput[left];
            const hRight = heightsInput[right];
            const width = right - left;
            const minHeight = Math.min(hLeft, hRight);
            const currentArea = width * minHeight;

            maxArea = Math.max(maxArea, currentArea);

            // Update variable tracker
            this.vars.put("left", left);
            this.vars.put("right", right);
            this.vars.put("currentArea", currentArea);
            this.vars.put("maxArea", maxArea);

            this.log(`Width: ${width}, Min Height: ${minHeight} (min of ${hLeft}, ${hRight}). Calculated Area: ${currentArea}.`);
            await this.await();

            // Decide which pointer to move
            if (hLeft < hRight) {
                this.log(`Left height (${hLeft}) is smaller than Right height (${hRight}). Moving left pointer inward.`);
                this.heights.highlight(left, null);
                left++;
            } else {
                this.log(`Right height (${hRight}) is smaller than or equal to Left height (${hLeft}). Moving right pointer inward.`);
                this.heights.highlight(right, null);
                right--;
            }

            // Update pointers in variables before next step
            this.vars.put("left", left);
            this.vars.put("right", right);
            await this.await();
        }

        this.log(`Algorithm finished. Maximum water found: ${maxArea}`);
        return maxArea;
    }
}
